module RefModule (
    input wire S,
    input wire R,
    input wire clk,
    output reg Q,
    output reg Qn
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (S && !R) begin
            Q <= 1'b1;
            Qn <= 1'b0;
        end else if (!S && R) begin
            Q <= 1'b0;
            Qn <= 1'b1;
        end else if (S && R) begin
            // Invalid state, hold previous state
        end
        // If both S and R are low, hold the state
    end
endmodule
